/**
 * ============================================================
 * SPD V13 — FIN SCENARIO RULE BRIDGE
 * ============================================================
 *
 * Connects:
 *
 * SCENARIO ENGINE
 *       ↓
 * FIN SCENARIO RULE MAP
 *       ↓
 * FIN RULE SELECTION
 *       ↓
 * CAPTAIN AI LENA
 *
 * Purpose:
 * Convert the active scenario generated by the Scenario Engine
 * into the applicable FIN rule context.
 *
 * The bridge does NOT make the final decision.
 * Captain AI Lena remains the decision authority.
 *
 * Flow:
 *
 * OPERATOR INPUT
 *      ↓
 * scenarioEngine()
 *      ↓
 * FX_SHOCK
 *      ↓
 * FIN SCENARIO RULE MAP
 *      ↓
 * FIN-001
 *      ↓
 * RULE VALIDATION
 *      ↓
 * CAPTAIN AI LENA
 * ============================================================
 */

import {
  FIN_SCENARIO_RULE_MAP,
  getFINRulesForScenario,
  validateFINRuleSelection,
  prepareFINRuleContext
} from "./fin-scenario-rule-map.js";


/**
 * ============================================================
 * SCENARIO → FIN DOMAIN MAP
 * ============================================================
 *
 * Maps Scenario Engine identifiers to FIN rule-map identifiers.
 *
 * FX_SHOCK is the official Scenario Engine identifier.
 * FX_STRESS is retained as an internal compatibility alias.
 * ============================================================
 */

const FIN_SCENARIO_ALIASES = {

  FX_SHOCK: "FX_SHOCK",

  FX_STRESS: "FX_SHOCK",

  BANKING_STRESS: "BANKING_STRESS"

};


/**
 * ============================================================
 * GET FIN SCENARIO ID
 * ============================================================
 *
 * Converts the active scenario into the identifier
 * used by the FIN Scenario Rule Map.
 * ============================================================
 */

export function getFINScenarioId(scenario) {

  const scenarioType =
    typeof scenario === "string"
      ? scenario
      : scenario?.type;

  const normalizedScenario =
    String(scenarioType ?? "NORMAL")
      .trim()
      .toUpperCase();

  return (
    FIN_SCENARIO_ALIASES[normalizedScenario] ??
    null
  );

}


/**
 * ============================================================
 * GET APPLICABLE FIN RULES
 * ============================================================
 *
 * Returns all FIN rules registered for the active scenario.
 *
 * This is used by the cockpit to display the rules
 * available for operator selection.
 * ============================================================
 */

export function getApplicableFINRules(scenario) {

  const finScenarioId =
    getFINScenarioId(scenario);

  if (!finScenarioId) {

    return {

      valid: false,

      status: "NO_FIN_SCENARIO",

      scenario: scenario,

      rules: []

    };

  }

  const rules =
    getFINRulesForScenario(
      finScenarioId
    );

  return {

    valid: true,

    status: "FIN_RULES_AVAILABLE",

    domain: "FIN",

    scenarioId:
      finScenarioId,

    rules

  };

}


/**
 * ============================================================
 * SELECT FIN RULE
 * ============================================================
 *
 * Validates the operator's selected FIN rule against
 * the active scenario.
 *
 * Invalid rule selections are rejected.
 * ============================================================
 */

export function selectFINRule(
  scenario,
  ruleId
) {

  const finScenarioId =
    getFINScenarioId(scenario);

  if (!finScenarioId) {

    return {

      valid: false,

      status: "NO_FIN_SCENARIO",

      message:
        "The active scenario is not mapped to the FIN domain."

    };

  }

  const validation =
    validateFINRuleSelection(
      finScenarioId,
      ruleId
    );

  if (!validation.valid) {

    return {

      valid: false,

      status:
        "RULE_SCENARIO_MISMATCH",

      domain: "FIN",

      scenarioId:
        finScenarioId,

      requestedRule:
        ruleId,

      message:
        validation.message

    };

  }

  return {

    valid: true,

    status:
      "FIN_RULE_SELECTED",

    domain: "FIN",

    scenarioId:
      finScenarioId,

    ruleId:
      validation.ruleId,

    ruleName:
      validation.ruleName

  };

}


/**
 * ============================================================
 * BUILD FIN RULE CONTEXT
 * ============================================================
 *
 * Creates the validated context passed to
 * Captain AI Lena's decision layer.
 * ============================================================
 */

export function buildFINRuleContext(
  scenario,
  ruleId
) {

  const selection =
    selectFINRule(
      scenario,
      ruleId
    );

  if (!selection.valid) {

    return selection;

  }

  const context =
    prepareFINRuleContext(
      selection.scenarioId,
      selection.ruleId
    );

  return {

    ...context,

    domain:
      "FIN",

    scenario:
      selection.scenarioId,

    selectedRule:
      selection.ruleId,

    ruleName:
      selection.ruleName,

    decisionAuthority:
      "CAPTAIN_AI_LENA",

    status:
      "FIN_RULE_CONTEXT_READY"

  };

}


/**
 * ============================================================
 * CAPTAIN AI LENA DECISION HANDOFF
 * ============================================================
 *
 * Final decision authority remains with Captain AI Lena.
 *
 * This function prepares a deterministic handoff packet.
 * It does not itself execute the final decision.
 * ============================================================
 */

export function buildFINLenaHandoff(
  scenario,
  ruleId,
  systemState = {}
) {

  const ruleContext =
    buildFINRuleContext(
      scenario,
      ruleId
    );

  if (!ruleContext.valid) {

    return ruleContext;

  }

  return {

    protocol:
      "SPD_V13",

    domain:
      "FIN",

    scenario:
      ruleContext.scenario,

    ruleId:
      ruleContext.selectedRule,

    ruleName:
      ruleContext.ruleName,

    systemState,

    decisionAuthority:
      "CAPTAIN_AI_LENA",

    decisionPipeline: [

      "OBSERVE",

      "VERIFY",

      "ASSESS",

      "DECIDE",

      "ACT",

      "UPDATE"

    ],

    status:
      "READY_FOR_CAPTAIN_AI_LENA_DECISION"

  };

}